pub struct sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread {
  // PLACEHOLDER MARKER STATE VARS,
  frame_period: i32,
  last_index: u32,
  prev_user_ch: hamr::ScheduleChannels,
  next_user_ch: hamr::ScheduleChannels,
  pre_p_producer: Option<PreState_p_producer>,
  pre_c_consumer: Option<PreState_c_consumer>,
  sys_assert_last_index: u32,
  sys_assert_ready: u64
}

impl sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread {
  pub fn new() -> Self
  {
    Self {
      frame_period: 0,
      last_index: u32::MAX,
      prev_user_ch: [0; hamr::hamr_ScheduleChannels_DIM_0],
      next_user_ch: [0; hamr::hamr_ScheduleChannels_DIM_0],
      pre_p_producer: None,
      pre_c_consumer: None,
      sys_assert_last_index: u32::MAX,
      sys_assert_ready: 0,
    }
  }

  pub fn initialize<API: sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Put_Api> (
    &mut self,
    api: &mut sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Application_Api<API>)
  {
    log_info("initialize entrypoint invoked");
  }

  pub fn timeTriggered<API: sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Full_Api> (
    &mut self,
    api: &mut sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Application_Api<API>)
  {
    self.gumbo_monitor(api);
    self.sys_assert_monitor(api);
  }

  pub fn notify(
    &mut self,
    channel: microkit_channel)
  {
    // this method is called when the monitor does not handle the passed in channel
    match channel {
      _ => {
        log_warn_channel(channel)
      }
    }
  }

  pub fn gumbo_monitor<API: sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Full_Api> (
    &mut self,
    api: &mut sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Application_Api<API>)
  {
    let state = api.get_sched_state();

    if self.last_index == u32::MAX {
      let schedule = api.get_sched_schedule();
      buildUserChannelTables(
        &schedule, &mut self.prev_user_ch, &mut self.next_user_ch);
    }

    // Detect schedule wraparound: if the current timeslice index is not
    // greater than the last one seen, the schedule has started a new frame
    if state.current_timeslice <= self.last_index {
      self.frame_period = self.frame_period + 1;
    }

    let idx = state.current_timeslice as usize;

    if self.last_index == u32::MAX {
      // First compute phase, check initialization guarantees
      {
        let post_p_producer = PostState_p_producer {
          count: api.get_p_producer_sv_count(),
          api_value: api.get_p_producer_value(),
        };
        if !crate::gumbox::p_producer_GUMBOX::initialize_IEP_Post(
          post_p_producer.count, post_p_producer.api_value) {
          log::warn!("*** CONTRACT VIOLATION: p_producer IEP_Post not satisfied ***");
          log::warn!("p_producer post: {:?}", post_p_producer);
        }
      }
      {
        let post_c_consumer = PostState_c_consumer {
          total: api.get_c_consumer_sv_total(),
        };
        if !crate::gumbox::c_consumer_GUMBOX::initialize_IEP_Post(
          post_c_consumer.total) {
          log::warn!("*** CONTRACT VIOLATION: c_consumer IEP_Post not satisfied ***");
          log::warn!("c_consumer post: {:?}", post_c_consumer);
        }
      }
    } else {
      let prev_ch = self.prev_user_ch[idx];
      match prev_ch {
        p_producer_MON => {
          let post = PostState_p_producer {
            count: api.get_p_producer_sv_count(),
            api_value: api.get_p_producer_value(),
          };
          if let Some(pre) = &self.pre_p_producer {
            if !crate::gumbox::p_producer_GUMBOX::compute_CEP_Post(
              pre.In_count, post.count, post.api_value) {
              log::warn!("*** CONTRACT VIOLATION: p_producer CEP_Post not satisfied ***");
              log::warn!("p_producer pre: {:?}", pre);
              log::warn!("p_producer post: {:?}", post);
            }
          } else {
            log::warn!("p_producer post check skipped: no saved pre-state");
          }
        }
        c_consumer_MON => {
          let post = PostState_c_consumer {
            total: api.get_c_consumer_sv_total(),
          };
          if let Some(pre) = &self.pre_c_consumer {
            if !crate::gumbox::c_consumer_GUMBOX::compute_CEP_Post(
              pre.In_total, post.total, pre.api_value) {
              log::warn!("*** CONTRACT VIOLATION: c_consumer CEP_Post not satisfied ***");
              log::warn!("c_consumer pre: {:?}", pre);
              log::warn!("c_consumer post: {:?}", post);
            }
          } else {
            log::warn!("c_consumer post check skipped: no saved pre-state");
          }
        }
        _ => {}
      }
    }

    let next_ch = self.next_user_ch[idx];
    match next_ch {
      p_producer_MON => {
        let pre = PreState_p_producer {
          In_count: api.get_p_producer_sv_count(),
        };
        self.pre_p_producer = Some(pre);
      }
      c_consumer_MON => {
        let pre = PreState_c_consumer {
          In_total: api.get_c_consumer_sv_total(),
          api_value: api.get_p_producer_value(),
        };
        self.pre_c_consumer = Some(pre);
      }
      _ => {}
    }

    self.last_index = state.current_timeslice;
  }

  pub fn sys_assert_monitor<API: sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Full_Api> (
    &mut self,
    api: &mut sys_assert_alt_monitor_process_sys_assert_alt_monitor_thread_Application_Api<API>)
  {
    let state = api.get_sched_state();

    if self.sys_assert_last_index == u32::MAX {
      let schedule = api.get_sched_schedule();
      buildUserChannelTables(
        &schedule, &mut self.prev_user_ch, &mut self.next_user_ch);
      validate_schedule_conformance(&schedule);
    }

    let idx = state.current_timeslice as usize;

    if self.sys_assert_last_index == u32::MAX {
      // First compute phase — initialize ready set and cascade
      self.sys_assert_ready = PLACE_START;
      self.sys_assert_ready = sys_assert_cascade(self.sys_assert_ready);
      self.sys_assert_last_index = state.current_timeslice;
      return;
    }

    let prev_ch = self.prev_user_ch[idx];

    match prev_ch {
      p_producer_MON => {
        self.sys_assert_ready = (self.sys_assert_ready & !PLACE_START) | PLACE_AFTER_PROD;
      }
      c_consumer_MON => {
        self.sys_assert_ready = (self.sys_assert_ready & !PLACE_AFTER_PROD) | PLACE_AFTER_CONS;
      }
      _ => {
        self.sys_assert_last_index = state.current_timeslice;
        return;
      }
    }

    // Fire splits/joins and collect all assertion places visited during the cascade
    let (final_ready, visited) = sys_assert_cascade_acc(self.sys_assert_ready);
    self.sys_assert_ready = final_ready;

    if visited & PLACE_AFTER_CONS != 0 {
      if !(sysProp_nonneg(api.get_c_consumer_sv_total())) {
        log::warn!("*** SYS ASSERT VIOLATION: property Alt_Consumer, after cons ***");
      }
    }

    if self.sys_assert_ready == PLACE_END {
      self.sys_assert_ready = PLACE_START;
      self.sys_assert_ready = sys_assert_cascade(self.sys_assert_ready);
    }

    self.sys_assert_last_index = state.current_timeslice;
  }
}

