pub fn hamr_SchedState_strategy_cust
  <last_yielded_ch_u32_strategy: Strategy<Value = u32>, 
   next_dispatch_ch_u32_strategy: Strategy<Value = u32>, 
   current_timeslice_u32_strategy: Strategy<Value = u32>> (
