use data::*;

macro_rules! implies {
  ($lhs: expr, $rhs: expr) => {
    !$lhs || $rhs
  };
}

macro_rules! impliesL {
  ($lhs: expr, $rhs: expr) => {
    !$lhs | $rhs
  };
}

/** Initialize EntryPointContract
  *
  * guarantee init_count
  *   counter starts at zero
  * @param count post-state state variable
  */
pub fn initialize_init_count(count: i32) -> bool
{
  count == 0i32
}

/** IEP-Guar: Initialize Entrypoint for producer
  *
  * @param count post-state state variable
  * @param api_value outgoing data port
  */
pub fn initialize_IEP_Guar(
  count: i32,
  api_value: i32) -> bool
{
  initialize_init_count(count)
}

/** IEP-Post: Initialize Entrypoint Post-Condition
  *
  * @param count post-state state variable
  * @param api_value outgoing data port
  */
pub fn initialize_IEP_Post(
  count: i32,
  api_value: i32) -> bool
{
  initialize_IEP_Guar(count, api_value)
}

/** Compute Entrypoint Contract
  *
  * guarantee out_nonneg
  *   output is non-negative
  * @param api_value outgoing data port
  */
pub fn compute_spec_out_nonneg_guarantee(api_value: i32) -> bool
{
  api_value >= 0i32
}

/** CEP-T-Guar: Top-level guarantee contracts for producer's compute entrypoint
  *
  * @param api_value outgoing data port
  */
pub fn compute_CEP_T_Guar(api_value: i32) -> bool
{
  let r0: bool = compute_spec_out_nonneg_guarantee(api_value);

  return r0;
}

/** CEP-Post: Compute Entrypoint Post-Condition for producer
  *
  * @param In_count pre-state state variable
  * @param count post-state state variable
  * @param api_value outgoing data port
  */
pub fn compute_CEP_Post(
  In_count: i32,
  count: i32,
  api_value: i32) -> bool
